sql.if:
AND ( EXISTS ( SELECT 1 FROM jwrki.tb_jobcls_ncs_map m WHERE m.NCS_CD IN
#{code}
AND m.JOBABA_GRP_CD = 'CMMN_276' AND m.JOBABA_CD = j.JOBABA_CMMN_276_CD AND m.USE_YN = 'Y' ) OR (
FIND_IN_SET(#{code}, REPLACE(COALESCE(j.JOBS_CD, ''), ' ', '')) > 0
) )

AND (
( FIND_IN_SET(#{code}, REPLACE(COALESCE(j.JOB_CAREER_CD, ''), ' ', '')) > 0 OR FIND_IN_SET(SUBSTRING(#{code}, 4, 1), REPLACE(COALESCE(j.JOB_CAREER_CD, ''), ' ', '')) > 0 OR FIND_IN_SET(CONCAT('0', SUBSTRING(#{code}, 4, 1)), REPLACE(COALESCE(j.JOB_CAREER_CD, ''), ' ', '')) > 0 OR (#{code} = 'R2010' AND TRIM(COALESCE(j.CAREER, '')) = '신입') OR (#{code} = 'R2020' AND TRIM(COALESCE(j.CAREER, '')) = '경력') OR (#{code} = 'R2030' AND REPLACE(TRIM(COALESCE(j.CAREER, '')), ' ', '') IN ('신입/경력', '신입+경력')) OR (#{code} = 'R2040' AND REPLACE(TRIM(COALESCE(j.CAREER, '')), ' ', '') IN ('외국인', '외국인전형')) )
)

AND (
( FIND_IN_SET(#{code}, REPLACE(COALESCE(j.JOB_ACDMCR_CD, ''), ' ', '')) > 0 OR FIND_IN_SET(SUBSTRING(#{code}, 4, 1), REPLACE(COALESCE(j.JOB_ACDMCR_CD, ''), ' ', '')) > 0 OR FIND_IN_SET(CONCAT('0', SUBSTRING(#{code}, 4, 1)), REPLACE(COALESCE(j.JOB_ACDMCR_CD, ''), ' ', '')) > 0 OR (#{code} = 'R7010' AND REPLACE(TRIM(COALESCE(j.MIN_EDUBG, '')), ' ', '') = '학력무관') OR (#{code} = 'R7020' AND REPLACE(TRIM(COALESCE(j.MIN_EDUBG, '')), ' ', '') IN ('중졸', '중졸이하')) OR (#{code} = 'R7030' AND REPLACE(TRIM(COALESCE(j.MIN_EDUBG, '')), ' ', '') = '고졸') OR (#{code} = 'R7040' AND REPLACE(TRIM(COALESCE(j.MIN_EDUBG, '')), ' ', '') IN ('대졸(2~3년)', '대졸(2-3년)')) OR (#{code} = 'R7050' AND REPLACE(TRIM(COALESCE(j.MIN_EDUBG, '')), ' ', '') = '대졸(4년)') OR (#{code} = 'R7060' AND TRIM(COALESCE(j.MIN_EDUBG, '')) = '석사') OR (#{code} = 'R7070' AND TRIM(COALESCE(j.MIN_EDUBG, '')) = '박사') )
)

AND (
( FIND_IN_SET(#{code}, REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0 OR (#{code} = '1' AND FIND_IN_SET('R1010', REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0) OR (#{code} = '2' AND FIND_IN_SET('R1020', REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0) OR (#{code} = '3' AND FIND_IN_SET('R1050', REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0) OR (#{code} = '3' AND FIND_IN_SET('R1060', REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0) OR (#{code} = '3' AND FIND_IN_SET('R1070', REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0) OR (#{code} = '1' AND FIND_IN_SET('10', REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0) OR (#{code} = '1' AND FIND_IN_SET('11', REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0) OR (#{code} = '2' AND FIND_IN_SET('20', REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0) OR (#{code} = '2' AND FIND_IN_SET('21', REPLACE(COALESCE(j.JOB_EMP_TP_CD, ''), ' ', '')) > 0) OR (#{code} = '1' AND FIND_IN_SET('정규직', REPLACE(COALESCE(j.EMP_TP_NM, ''), ' ', '')) > 0) OR (#{code} = '2' AND FIND_IN_SET('계약직', REPLACE(COALESCE(j.EMP_TP_NM, ''), ' ', '')) > 0) OR (#{code} = '3' AND FIND_IN_SET('인턴직', REPLACE(COALESCE(j.EMP_TP_NM, ''), ' ', '')) > 0) OR (#{code} = '6' AND FIND_IN_SET('프리랜서', REPLACE(COALESCE(j.EMP_TP_NM, ''), ' ', '')) > 0) OR (#{code} = '7' AND FIND_IN_SET('아르바이트', REPLACE(COALESCE(j.EMP_TP_NM, ''), ' ', '')) > 0) )
)

AND (
( FIND_IN_SET(#{code}, REPLACE(COALESCE(j.JOB_CAREER_CD, ''), ' ', '')) > 0 OR (#{code} = '1' AND FIND_IN_SET('R2010', REPLACE(COALESCE(j.JOB_CAREER_CD, ''), ' ', '')) > 0) OR (#{code} = '2' AND FIND_IN_SET('R2020', REPLACE(COALESCE(j.JOB_CAREER_CD, ''), ' ', '')) > 0) OR (#{code} = '3' AND FIND_IN_SET('R2030', REPLACE(COALESCE(j.JOB_CAREER_CD, ''), ' ', '')) > 0) OR (#{code} = '1' AND TRIM(COALESCE(j.CAREER, '')) = '신입') OR (#{code} = '2' AND TRIM(COALESCE(j.CAREER, '')) = '경력') OR (#{code} = '3' AND REPLACE(TRIM(COALESCE(j.CAREER, '')), ' ', '') IN ('신입/경력', '신입+경력')) OR (#{code} = '4' AND REPLACE(TRIM(COALESCE(j.CAREER, '')), ' ', '') IN ('관계없음', '경력무관')) )
)

AND (
( FIND_IN_SET(#{code}, REPLACE(COALESCE(j.JOB_ACDMCR_CD, ''), ' ', '')) > 0 OR (#{code} = '0' AND FIND_IN_SET('R7010', REPLACE(COALESCE(j.JOB_ACDMCR_CD, ''), ' ', '')) > 0) OR (#{code} = '3' AND FIND_IN_SET('R7030', REPLACE(COALESCE(j.JOB_ACDMCR_CD, ''), ' ', '')) > 0) OR (#{code} = '4' AND FIND_IN_SET('R7040', REPLACE(COALESCE(j.JOB_ACDMCR_CD, ''), ' ', '')) > 0) OR (#{code} = '5' AND FIND_IN_SET('R7050', REPLACE(COALESCE(j.JOB_ACDMCR_CD, ''), ' ', '')) > 0) OR (#{code} = '7' AND FIND_IN_SET('R7070', REPLACE(COALESCE(j.JOB_ACDMCR_CD, ''), ' ', '')) > 0) OR (#{code} = '0' AND REPLACE(TRIM(COALESCE(j.MIN_EDUBG, '')), ' ', '') = '학력무관') OR (#{code} = '3' AND REPLACE(TRIM(COALESCE(j.MIN_EDUBG, '')), ' ', '') = '고졸') OR (#{code} = '4' AND REPLACE(TRIM(COALESCE(j.MIN_EDUBG, '')), ' ', '') IN ('대졸(2~3년)', '대졸(2-3년)')) OR (#{code} = '5' AND REPLACE(TRIM(COALESCE(j.MIN_EDUBG, '')), ' ', '') = '대졸(4년)') OR (#{code} = '7' AND TRIM(COALESCE(j.MIN_EDUBG, '')) = '박사') )
)

AND (
    COALESCE(
        NULLIF(TRIM(j.SAL_TP_NM), ''),
        CASE
            WHEN COALESCE(j.SAL_AMT, '') LIKE '%연봉%' THEN '연봉'
            WHEN COALESCE(j.SAL_AMT, '') LIKE '%월급%' THEN '월급'
            WHEN COALESCE(j.SAL_AMT, '') LIKE '%일급%' THEN '일급'
            WHEN COALESCE(j.SAL_AMT, '') LIKE '%시급%' THEN '시급'
            ELSE NULL
        END
    ) = #{salaryType}

        AND REPLACE(COALESCE(j.SAL_AMT, ''), ',', '') REGEXP '[0-9]+'


        AND (
            CASE
                WHEN REPLACE(COALESCE(j.SAL_AMT, ''), ',', '') LIKE '%~%'
                    THEN CAST(REGEXP_SUBSTR(
                        SUBSTRING_INDEX(REPLACE(COALESCE(j.SAL_AMT, ''), ',', ''), '~', -1),
                        '[0-9]+'
                    ) AS DECIMAL(20, 0))
                ELSE CAST(REGEXP_SUBSTR(
                    REPLACE(COALESCE(j.SAL_AMT, ''), ',', ''),
                    '[0-9]+'
                ) AS DECIMAL(20, 0))
            END
        ) >= #{salaryMin}


        AND CAST(REGEXP_SUBSTR(
            REPLACE(COALESCE(j.SAL_AMT, ''), ',', ''),
            '[0-9]+'
        ) AS DECIMAL(20, 0)) <= #{salaryMax}

)
